CREATE DATABASE IF NOT EXISTS daily_practice_20260412_schema;
USE daily_practice_20260412_schema;

-- This table logs the total daily revenue generated by sales representatives.
CREATE TABLE daily_sales (
    log_id INT PRIMARY KEY AUTO_INCREMENT,
    rep_id INT,
    sale_date DATE,
    revenue DECIMAL(10, 2)
);

